module RefModule (
    input clk,
    input rst,
    input d,
    output q
);

    reg unused_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_q_reg <= 1'b0;
        else
            unused_q_reg <= d;
    end

    assign q = unused_q_reg;

endmodule
